    ('Frees', 'Protein Shot', 'https://images.openfoodfacts.org/images/products/590/606/851/8868/front_pl.3.400.jpg', 'off_api', 'front', true, 'Front — EAN 5906068518868', 'front_5906068518868'),
    ('Vital Fresh', 'Smoothie Owoce Leśne', 'https://images.openfoodfacts.org/images/products/841/026/171/8224/front_pl.9.400.jpg', 'off_api', 'front', true, 'Front — EAN 8410261718224', 'front_8410261718224'),
    ('Unknown', 'Vita Aloe', 'https://images.openfoodfacts.org/images/products/590/513/352/8733/front_it.3.400.jpg', 'off_api', 'front', true, 'Front — EAN 5905133528733', 'front_5905133528733'),
    ('Cappy', 'Cappy Jabłkowy 1l', 'https://images.openfoodfacts.org/images/products/544/900/019/1380/front_pl.4.400.jpg', 'off_api', 'front', true, 'Front — EAN 5449000191380', 'front_5449000191380'),
    ('Coca-Cola', 'Coca-Cola Original Taste', 'https://images.openfoodfacts.org/images/products/544/900/000/0996/front_en.1002.400.jpg', 'off_api', 'front', true, 'Front — EAN 5449000000996', 'front_5449000000996'),
    ('Coca-Cola', 'Coca-Cola Zero Sugar', 'https://images.openfoodfacts.org/images/products/544/900/013/1805/front_en.687.400.jpg', 'off_api', 'front', true, 'Front — EAN 5449000131805', 'front_5449000131805'),
    ('Coca-Cola', 'Original Taste', 'https://images.openfoodfacts.org/images/products/000/005/449/1472/front_en.694.400.jpg', 'off_api', 'front', true, 'Front — EAN 54491472', 'front_54491472'),
