    ('Monster Energy Company', 'Monster energy ultra', 'https://images.openfoodfacts.org/images/products/506/033/750/0258/front_en.6.400.jpg', 'off_api', 'front', true, 'Front — EAN 5060337500258', 'front_5060337500258')
) AS d(brand, product_name, url, source, image_type, is_primary, alt_text, off_image_id)
JOIN products p ON p.country = 'PL' AND p.brand = d.brand AND p.product_name = d.product_name
  AND p.category = 'Drinks' AND p.is_deprecated IS NOT TRUE
ON CONFLICT (off_image_id) WHERE off_image_id IS NOT NULL DO UPDATE SET
  url = EXCLUDED.url,
  image_type = EXCLUDED.image_type,
  is_primary = EXCLUDED.is_primary,
  alt_text = EXCLUDED.alt_text;
